mapper.update:
update post
title = #{title}, price = #{price}, description = #{description}, status = #{status}, publishTime = #{publishTime}, updateTime = #{updateTime}, viewCount = #{viewCount}, mediaFiles = #{mediaFiles}, aiValuationRange = #{aiValuationRange}, city = #{city}, boilerId = #{boilerId},
where postId = #{postId}

update post
set viewCount = ifnull(viewCount, 0) + 1
where postId = #{postId}

mapper.select:
select p.*
from post p
where p.status = 'PUBLISHED'


        order by p.${sortField} ${sortOrder}


        order by p.updateTime desc, p.publishTime desc


limit #{offset}, #{pageSize}

select p.*
from post p
inner join boiler b on p.boilerId = b.boilerId



        order by p.${sortField} ${sortOrder}


        order by p.updateTime desc, p.publishTime desc


limit #{offset}, #{pageSize}

select p.*
from post p
left join boiler b on p.boilerId = b.boilerId



        order by p.${sortField} ${sortOrder}


        order by p.updateTime desc, p.publishTime desc, p.postId desc


limit #{offset}, #{pageSize}
